ALTER TABLE sp_acumulados DROP CONSTRAINT sp_acumulados_fuente_check;
ALTER TABLE sp_acumulados ADD CONSTRAINT sp_acumulados_fuente_check CHECK (fuente = ANY (ARRAY['CONVERSION_COP','CUMPLIMIENTO_META','RETO_DIARIO','RETO_SEMANAL','RETO_MENSUAL','MEDALLA','RECONOCIMIENTO_RECIBIDO','RECONOCIMIENTO_ENVIADO']));